from functools import wraps

def retry(n=3):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for tentativo in range(n):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    print(f"Tentativo {tentativo+1} fallito")
                    if tentativo == n - 1: raise
        return wrapper
    return decorator

tentativi = [0]

@retry(n=3)
def chiama():
    tentativi[0] += 1
    if tentativi[0] < 3:
        raise ValueError("non ancora pronto")
    print("Successo!")

chiama()

